SELECT number_files
  FROM data_ingests
 WHERE ingest_id = 0;

SELECT SUM(number_files) AS total_files_ingested
FROM data_ingests
WHERE platform = 'GP05MOAS';

SELECT ingest_id
FROM data_ingests
WHERE status = 'Failed';

SELECT filename
FROM file_status
WHERE status = 'Failed' AND retries > 2;

SELECT COUNT(*) AS failed_file_count
  FROM file_status
  WHERE status = 'Failed';

SELECT ingest_id, number_files AS total_files_ingested
  FROM data_ingests
  ORDER BY number_files DESC;

SELECT platform
FROM data_ingests
ORDER BY ingest_start_time DESC;

SELECT DISTINCT platform
FROM data_ingests
ORDER BY platform;

SELECT ingest_id
FROM data_ingests
WHERE ingest_end_time = (SELECT MAX(ingest_end_time) FROM data_ingests);

SELECT number_files AS total_files_ingested
FROM data_ingests
WHERE ingest_id = 0;

SELECT data_source, SUM(number_files) AS total_files_ingested
FROM data_ingests
GROUP BY data_source;
